package com.rabitah.frontend;
import com.rabitah.frontend.api.*; import com.rabitah.frontend.navigation.SceneRouter; import com.rabitah.frontend.session.SessionManager; import java.net.URI; import java.util.concurrent.*;
public final class AppContext implements AutoCloseable {private final ExecutorService executor=Executors.newVirtualThreadPerTaskExecutor();private final SessionManager session=new SessionManager();private final ApiClient api=new ApiClient(URI.create(System.getProperty("rabitah.api","http://localhost:8080/api/v1/")),session,executor);private final AuthApiService auth=new AuthApiService(api);private final SceneRouter router=new SceneRouter(this);public SessionManager session(){return session;}public AuthApiService auth(){return auth;}public ApiClient api(){return api;}public SceneRouter router(){return router;}public Executor executor(){return executor;}@Override public void close(){session.clear();executor.shutdownNow();}}
